class Solution:
    def getMaxFunctionValue(self, receiver: List[int], k: int) -> int:
        n = len(receiver)
        max_val = 0
        for x in range(n):
            current = x
            total = x
            for _ in range(k):
                current = receiver[current]
                total += current
            max_val = max(max_val, total)
        return max_val
